// src/components/TelaCaixas.jsx
import React, { useState, useEffect } from 'react'
import axios from 'axios'

export default function TelaCaixas() {
  const [caixas, setCaixas] = useState([])
  const [nome, setNome] = useState('')
  const [codigo, setCodigo] = useState('')

  useEffect(() => {
    fetchCaixas()
  }, [])

  async function fetchCaixas() {
    try {
      const { data } = await axios.get('/api/caixas')
      setCaixas(data)
    } catch (err) {
      console.error(err)
    }
  }

  async function handleSubmit(e) {
    e.preventDefault()
    try {
      await axios.post('/api/caixas', {
        nome,
        // Se o usuário deixar em branco, backend gera EAN-13 automaticamente
        ...(codigo && { codigo_barras: codigo })
      })
      setNome('')
      setCodigo('')
      fetchCaixas()
    } catch (err) {
      console.error(err)
      alert('Erro ao cadastrar caixa')
    }
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4 space-y-6">
      <h2 className="text-2xl font-bold">Gerenciar Caixas</h2>

      {/* formulário em card */}
      <div className="bg-white rounded-2xl shadow p-6">
        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <input
            className="col-span-1 md:col-span-2 w-full border rounded px-3 py-2"
            placeholder="Nome da Caixa"
            value={nome}
            onChange={e => setNome(e.target.value)}
            required
          />
          <input
            className="w-full border rounded px-3 py-2"
            placeholder="Código de Barras (opcional)"
            value={codigo}
            onChange={e => setCodigo(e.target.value)}
            // removed required here
          />
          <button
            type="submit"
            className="h-fit self-end bg-blue-600 hover:bg-blue-700 text-white font-bold px-4 py-2 rounded-full"
          >
            Cadastrar
          </button>
        </form>
      </div>

      {/* lista em card */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h3 className="text-xl font-bold mb-4">Caixas Cadastradas</h3>
        <div className="grid grid-cols-1 gap-4">
          {caixas.map(c => (
            <div
              key={c.id}
              className="flex items-center justify-between bg-gray-50 rounded-lg p-4 hover:bg-gray-100 transition"
            >
              <div>
                <p className="font-semibold">{c.nome}</p>
                <p className="text-sm text-gray-600">#{c.id} – {c.codigo_barras}</p>
              </div>
              <div className="flex gap-2">
                <button
                  onClick={() => {/* editar lógica */}}
                  className="px-3 py-1 rounded-full bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
                >
                  Editar
                </button>
                <button
                  onClick={async () => {
                    if(!window.confirm('Deseja realmente excluir esta caixa?')) return;
                    try {
                      await axios.delete(`/api/caixas/${c.id}`)
                      setCaixas(prev => prev.filter(x => x.id !== c.id))
                    } catch {
                      alert('Erro ao excluir caixa')
                    }
                  }}
                  className="px-3 py-1 rounded-full bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
                >
                  Deletar
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
